import ast, sys, os

def check_empty_except(filepath):
    findings = []
    try:
        with open(filepath) as f:
            source = f.read()
        tree = ast.parse(source, filepath)
    except:
        return []

    for node in ast.walk(tree):
        if isinstance(node, ast.ExceptHandler):
            # Check if body is just 'pass' with no comment
            if len(node.body) == 1 and isinstance(node.body[0], ast.Pass):
                # Read the actual line to check if there's a comment
                lines = source.split('\n')
                line_idx = node.body[0].lineno - 1
                line_text = lines[line_idx] if line_idx < len(lines) else ''
                # Check if there's a comment on the pass line or around it
                has_comment = '#' in line_text
                # Also check line before
                if not has_comment and line_idx > 0:
                    prev_line = lines[line_idx - 1]
                    # Check if the except line itself has a comment
                    # The except handler starts at node.lineno
                    except_line = lines[node.lineno - 1] if node.lineno - 1 < len(lines) else ''
                    has_comment = '#' in except_line
                if not has_comment:
                    findings.append((filepath, node.lineno, node.body[0].lineno))
    return findings

for root, dirs, files in os.walk('src'):
    for f in files:
        if f.endswith('.py'):
            fp = os.path.join(root, f)
