def check_unused_vars(filepath):
    findings = []
    try:
        with open(filepath) as f:
            source = f.read()
        tree = ast.parse(source, filepath)
    except:
        return []

    # Check for assignment targets that are never read
    # This is a simple heuristic, not a full-blown analysis
    for node in ast.walk(tree):
        if isinstance(node, ast.Assign) and len(node.targets) == 1:
            target = node.targets[0]
            if isinstance(target, ast.Name):
                name = target.id
                if name.startswith('_') and not name.startswith('__'):
                    continue  # Convention for unused
                # Skip common patterns
                if name in ('logger', 'console', 'app', 'bp', 'db', 'Base'):
