import os, re

def find_commented_blocks(filepath, min_lines=4):
    findings = []
    try:
        with open(filepath) as f:
            lines = f.readlines()
    except:
        return []

    block_start = None
    block_lines = 0

    for i, line in enumerate(lines, 1):
        stripped = line.strip()
        # Check if this line is a comment (not a docstring or decorator)
        if stripped.startswith('#') and not stripped.startswith('#!') and not stripped.startswith('# ---'):
            # Skip single-word comments like # type: ignore, # noqa, # pylint
            # and section headers (containing only non-code)
            if block_start is None:
                block_start = i
                block_lines = 1
            else:
                block_lines += 1
        else:
            if block_lines >= min_lines:
                # Check if this looks like commented-out code vs regular comments
                block_text = ''.join(lines[block_start-1:block_start-1+block_lines])
                # Heuristic: commented-out code typically has = signs, (), def/class/import keywords
                code_indicators = ['=', '(', 'def ', 'class ', 'import ', 'from ', 'return ', 'if ', 'for ', 'while ', 'await ']
                has_code_indicator = any(ind in block_text for ind in code_indicators)
                if has_code_indicator:
                    findings.append((filepath, block_start, block_lines, block_text[:200]))
            block_start = None
            block_lines = 0

    # Handle block at end of file
    if block_lines >= min_lines:
        block_text = ''.join(lines[block_start-1:block_start-1+block_lines])
        code_indicators = ['=', '(', 'def ', 'class ', 'import ', 'from ', 'return ', 'if ', 'for ', 'while ']
        has_code_indicator = any(ind in block_text for ind in code_indicators)
        if has_code_indicator:
            findings.append((filepath, block_start, block_lines, block_text[:200]))

    return findings

for root, dirs, files in os.walk('src'):
    for f in files:
        if f.endswith('.py'):
            fp = os.path.join(root, f)
            results = find_commented_blocks(fp)
            for filepath, start, count, preview in results:
                print(f'{filepath}:{start} ({count} lines)')
                for line in preview.split(chr(10))[:4]:
                    print(f'  {line}')
                print()

for root, dirs, files in os.walk('tests'):
